),
source_rows AS (
  SELECT
    r.id AS roll_id,
    v.id AS variant_id,
    src.qty,
    src.unit,
    src.rate,
    src.bill_no
  FROM src
  JOIN inv_products p ON p.normalized_name = src.normalized_product
  JOIN inv_categories c ON c.id = p.category_id
  JOIN inv_variants v ON v.product_id = p.id AND v.normalized_name = src.normalized_variant
  JOIN inv_rolls r ON r.variant_id = v.id AND r.batch_code = src.batch_code AND r.notes = 'Import: Main Data for MTR Vertical'
  WHERE c.normalized_name = 'vertical blind fabrics'
)
UPDATE inv_movements m
SET quantity = s.qty,
    unit = s.unit,
    rate = s.rate,
    reference = s.bill_no,
    note = 'Initial vertical blind stock import'
FROM source_rows s
WHERE m.roll_id = s.roll_id
  AND m.movement_type = 'inflow'
  AND m.note = 'Initial vertical blind stock import';

